 1	import * as React from 'react';
 2	import {
 3	  EmptyState,
 4	  EmptyStateBody,
 5	  EmptyStateVariant,
 6	  PageSection,
 7	} from '@patternfly/react-core';
 8	import { useTranslation } from 'react-i18next';
 9	import { PipelineRunModel } from '../../models';
10	import { PipelineRunKind } from '../../types';
11	
12	import ResultsList from './ResultsList';
13	
14	const OutputTab: React.FC<{ obj: PipelineRunKind }> = ({
15	  obj: pipelineRun,
16	}) => {
17	  const { t } = useTranslation('plugin__pipelines-console-plugin');
18	
19	  return pipelineRun.status?.pipelineResults || pipelineRun.status?.results ? (
20	    <PageSection variant="light" isFilled>
21	      <ResultsList
22	        results={
23	          pipelineRun.status?.pipelineResults || pipelineRun.status?.results
24	        }
25	        resourceName={t(PipelineRunModel.labelKey)}
26	      />
27	    </PageSection>
28	  ) : (
29	    <EmptyState variant={EmptyStateVariant.full}>
30	      <EmptyStateBody>
31	        <p>{t('No Output found')}</p>
32	      </EmptyStateBody>
33	    </EmptyState>
34	  );
35	};
36	export default OutputTab;

